import React from "react";
import { Reveal } from "./Reveal";

// Estilos de fuentes integrados directamente
const fontStyles = `
  @font-face {
    font-family: 'BodoniStd';
    src: url('/forts/As_BodoniStd.off') format('opentype');
    font-weight: normal;
    font-style: normal;
    font-display: swap;
  }

  @font-face {
    font-family: 'TrajanPro';
    src: url('/forts/As_TrajanProRegular.tif') format('truetype');
    font-weight: normal;
    font-style: normal;
    font-display: swap;
  }

  .font-bodoni {
    font-family: 'BodoniStd', serif;
  }

  .font-trajan {
    font-family: 'TrajanPro', serif;
  }
`;

// Insertar estilos en el head del documento
if (typeof document !== 'undefined') {
  const styleElement = document.createElement('style');
  styleElement.textContent = fontStyles;
  document.head.appendChild(styleElement);
}

export default function NosotrosSection() {
  return (
    <section id="about" className="relative overflow-hidden scroll-mt-24 bg-gradient-to-br from-[#F4E9D7] to-[#F4E9D7]/80 min-h-screen flex items-center">
      {/* Pattern background */}
      <div aria-hidden className="pointer-events-none absolute inset-0">
        <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,')] opacity-20" />
        
        {/* Geometric shapes */}
        <div className="absolute top-10 right-10 w-40 h-40 border-4 border-[#072D42]/10 rounded-lg rotate-12" />
        <div className="absolute bottom-20 left-10 w-32 h-32 border-4 border-[#F29E38]/20 rounded-full" />
        <div className="absolute top-1/3 left-1/4 w-24 h-24 border-4 border-[#072D42]/15 rotate-45" />
        
        {/* Accent elements */}
        <div className="absolute top-1/4 right-1/3 w-16 h-1 bg-[#F29E38] rotate-45" />
        <div className="absolute bottom-1/3 left-20 w-12 h-1 bg-[#F29E38] rotate-45" />
      </div>

      <div className="container mx-auto px-4 py-16 relative">
        <Reveal>
          <div className="mx-auto max-w-5xl rounded-2xl bg-white/95 backdrop-blur-md shadow-2xl border border-[#072D42]/10 transform transition-all duration-300 hover:shadow-3xl">
            <div className="p-10 md:p-14 relative overflow-hidden">
              {/* Corner accents */}
              <div className="absolute top-0 left-0 w-16 h-16 border-t-4 border-l-4 border-[#F29E38] rounded-tl-2xl" />
              <div className="absolute top-0 right-0 w-16 h-16 border-t-4 border-r-4 border-[#F29E38] rounded-tr-2xl" />
              <div className="absolute bottom-0 left-0 w-16 h-16 border-b-4 border-l-4 border-[#F29E38] rounded-bl-2xl" />
              <div className="absolute bottom-0 right-0 w-16 h-16 border-b-4 border-r-4 border-[#F29E38] rounded-br-2xl" />
              
              <p className="uppercase tracking-widest text-xs md:text-sm text-[#072D42]/70 font-semibold font-trajan">Sobre nosotros</p>
              <h1 className="font-bodoni text-5xl md:text-6xl text-[#072D42] mt-4 leading-tight">
                Orbis <span className="text-[#072D42]">Empresarial</span>
              </h1>
              
              <div className="h-1 w-20 bg-[#F29E38] my-6" />
              
              <p className="text-lg md:text-xl text-[#072D42]/90 mt-6 leading-relaxed font-light font-trajan">
                Plataforma dedicada a investigar, preservar y difundir la memoria empresarial de Bolivia. 
                <span className="block mt-3 font-medium">Narramos historias con rigor, sensibilidad y profundidad, conectando pasado y futuro para inspirar a nuevas generaciones.</span>
              </p>
              
              <div className="mt-8 flex flex-wrap gap-4">
                <span className="inline-flex items-center rounded-full bg-[#072D42] px-4 py-2 text-sm text-white font-medium shadow-lg font-trajan">
                  Archivo vivo
                </span>
                <span className="inline-flex items-center rounded-full bg-[#F29E38] px-4 py-2 text-sm text-white font-medium shadow-lg font-trajan">
                  Curaduría rigurosa
                </span>
                <span className="inline-flex items-center rounded-full bg-[#072D42] px-4 py-2 text-sm text-white font-medium shadow-lg font-trajan">
                  Acceso responsable
                </span>
              </div>
            </div>
          </div>
        </Reveal>

        {/* Supporting cards */}
        <div className="mt-16 grid gap-8 md:grid-cols-3">
          <Reveal>
            <div className="rounded-xl bg-white/95 p-8 shadow-xl border border-[#072D42]/10 transform transition-all duration-300 hover:-translate-y-2 hover:shadow-2xl group relative overflow-hidden">
              <div className="absolute inset-0 bg-gradient-to-br from-[#072D42]/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
              <div className="relative">
                <div className="w-12 h-12 bg-[#072D42] rounded-lg flex items-center justify-center mb-4">
                  <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                  </svg>
                </div>
                <h3 className="font-bodoni text-2xl text-[#072D42]">Rigor</h3>
                <div className="h-1 w-8 bg-[#F29E38] my-3" />
                <p className="text-[#072D42]/80 leading-relaxed font-trajan">
                  Metodologías de documentación confiables, verificación de fuentes y estándares editoriales claros.
                </p>
              </div>
            </div>
          </Reveal>
          
